def shortestBeautifulSubstring(s: str, k: int) -> str:
    n = len(s)
    best = None

    # Count ones in each possible substring
    for i in range(n):
        count_ones = 0
        for j in range(i, n):
            if s[j] == '1':
                count_ones += 1
            if count_ones == k:
                length = j - i + 1
                candidate = s[i:j+1]
                if best is None or length < len(best) or (length == len(best) and candidate < best):
                    best = candidate
                break  # No need to extend further, as it will only get longer
            elif count_ones > k:
                break

    return best if best is not None else ""
